import pytest
import uuid

def test_pin_change_single_valid_request(api_client, owned_card_id, reset_pin_change_counter):
    idempotency_key = str(uuid.uuid4())
    payload = {"new_pin": "<valid_pin>"}
    headers = {"Idempotency-Key": idempotency_key}

    response = api_client.patch(
        f"/cards/{owned_card_id}/pin",
        json=payload,
        headers=headers
    )

    assert response.status_code in (200, 204), (
        f"Expected 200 or 204, got {response.status_code}: {response.text}"
    )

