def test_pin_change_idempotent_duplicate_key_returns_original_result(
    api_client, owned_card_id, reset_pin_change_counter
):
    idempotency_key = str(uuid.uuid4())
    payload = {"new_pin": "<valid_pin>"}
    headers = {"Idempotency-Key": idempotency_key}

    first = api_client.patch(
        f"/cards/{owned_card_id}/pin", json=payload, headers=headers
    )
    second = api_client.patch(
        f"/cards/{owned_card_id}/pin", json=payload, headers=headers
    )

    assert first.status_code in (200, 204)
    assert second.status_code == first.status_code
    assert second.json() == first.json(), "Idempotent responses must match"
    count = get_pin_change_count(api_client, owned_card_id)
    assert count == 1, f"Counter should be 1, got {count}"

