import pytest
import uuid

def test_pin_change_state_transitions_fresh_to_rate_limited(
    api_client, owned_card_id, reset_pin_change_counter
):
    for i in range(5):
        resp = api_client.patch(
            f"/cards/{owned_card_id}/pin",
            json={"new_pin": f"<valid_pin_{i}>"},
            headers={"Idempotency-Key": str(uuid.uuid4())}
        )
        assert resp.status_code in (200, 204), (
            f"Change {i+1} should succeed, got {resp.status_code}"
        )

    sixth = api_client.patch(
        f"/cards/{owned_card_id}/pin",
        json={"new_pin": "<valid_pin_6>"},
        headers={"Idempotency-Key": str(uuid.uuid4())}
    )
    assert sixth.status_code == 429, (
        f"6th change must be blocked with 429, got {sixth.status_code}"
    )
